id Online</td><td style=\"padding:8px 0;text-align:right;font-weight:700;color:#15803d;\">R{{ $node['Get Booking from Supabase'].json.amount_paid }}</td></tr><tr style=\"font-size:18px;\"><td style=\"padding:15px 0 0 0;border-top:2px solid #e5e7eb;font-weight:800;color:#111827;\">BALANCE DUE</td><td style=\"padding:15px 0 0 0;border-top:2px solid #e5e7eb;text-align:right;font-weight:800;color:#b45309;\">R{{ $node['Get Booking from Supabase'].json.total_price - $node['Get Booking from Supabase'].json.amount_paid }}</td></tr></table></div><div style=\"margin-top:30px;text-align:center;\"><a href=\"https://themulligan.org/admin\" style=\"display:inline-block;background-color:#1a472a;color:#ffffff;padding:15px 30px;border-radius:8px;text-decoration:none;font-weight:700;font-size:14px;box-shadow:0 4px 6px rgba(0,0,0,0.1);\">OPEN ADMIN DASHBOARD</a></div><p style=\"margin-top:25px;font-size:12px;color:#9ca3af;text-align:center;\">This is an automated operational notification.<br>The Mulligan Golf Lounge</p></div></div>"
