  "subject": "Booking Confirmed - The Mulligan",
  "html": "<div style=\"font-family:sans-serif;max-width:600px;margin:0 auto;background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 10px 25px rgba(0,0,0,0.05);\"><div style=\"background-color:#1a472a;background-image:linear-gradient(135deg,#1a472a 0%,#0d2a19 100%);padding:60px 40px;text-align:center;\"><div style=\"display:inline-block;background:rgba(255,255,255,0.1);border:1px solid rgba(255,255,255,0.2);color:#fff;padding:6px 16px;border-radius:100px;font-size:12px;font-weight:600;margin-bottom:20px;\">SESSION CONFIRMED</div><p style=\"color:#fff;font-size:24px;font-weight:800;letter-spacing:-0.5px;margin:0 0 8px;\">The Mulligan</p><p style=\"color:#fbbf24;font-size:12px;font-weight:600;text-transform:uppercase;letter-spacing:2px;margin:0 0 30px;opacity:0.9;\">The Simulator Never Judges</p><h1 style=\"color:#fff;font-size:32px;font-weight:700;margin:0;line-height:1.2;\">You're Teeing Off!</h1><p style=\"color:#a3d9a5;font-size:16px;margin:12px 0 0;opacity:0.8;\">See you on the green, {{ $node['Get Booking from Supabase'].json.guest_name }}.</p></div><div style=\"padding:40px;\"><p style=\"font-size:18px;color:#111827;font-weight:600;margin:0 0 16px;\">Exciting news, {{ $node['Get Booking from Supabase'].json.guest_name }}!</p><p style=\"font-size:15px;color:#4b5563;line-height:1.6;margin:0 0 32px;\">Your booking at The Mulligan is confirmed. We've reserved Bay {{ $node['Get Booking from Supabase'].json.simulator_id }} exclusively for your group. Fasten your spikes and get ready for a world-class indoor golf experience.</p><div style=\"background-color:#f9fafb;border:1px solid #f3f4f6;border-radius:12px;padding:24px;margin-bottom:32px;\"><span style=\"font-size:12px;font-weight:700;color:#9ca3af;text-transform:uppercase;letter-spacing:1px;margin-bottom:20px;display:block;\">Booking Specifications</span><table style=\"width:100%;border-collapse:collapse;\"><tr><td style=\"padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#6b7280;text-align:left;\">Date</td><td style=\"padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#111827;font-weight:600;text-align:right;\">{{ $node['Get Booking from Supabase'].json.booking_date }}</td></tr><tr><td style=\"padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#6b7280;text-align:left;\">Start Time</td><td style=\"padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#111827;font-weight:600;text-align:right;\">{{ $node['Get Booking from Supabase'].json.start_time }}</td></tr><tr><td style=\"padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#6b7280;text-align:left;\">Duration</td><td style=\"padding:12px 0;border-bottom:1px solid #f3f4f6;font-size:14px;color:#111827;font-weight:600;text-align:right;\">{{ $node['Get Booking from Supabase'].json.duration_hours }} Hours</td></tr><tr><td style=\"padding:12px 0;font-size:14px;color:#6b7280;text-align:left;\">Players</td><td style=\"padding:12px 0;font-size:14px;color:#111827;font-weight:600;text-align:right;\">{{ $node['Get Booking from Supabase'].json.player_count }} Players</td></tr></table></div><div style=\"background-color:#ecfdf5;border:1px solid #d1fae5;border-radius:12px;padding:24px;margin-bottom:32px;text-align:center;\"><span style=\"font-size:13px;color:#065f46;opacity:0.7;margin-bottom:12px;display:block;font-weight:500;\">SECURED VIA DEPOSIT</span><p style=\"font-size:28px;font-weight:700;color:#065f46;margin:0;\">R{{ $node['Get Booking from Supabase'].json.amount_paid }} Paid</p><div style=\"margin-top:16px;padding-top:16px;border-top:1px solid rgba(6,95,70,0.1);display:flex;justify-content:center;align-items:center;gap:8px;\"><span style=\"font-size:14px;color:#065f46;font-weight:500;\">Balance Due at Venue:</span><span style=\"font-size:18px;font-weight:700;color:#92400e;\">R{{ $node['Get Booking from Supabase'].json.total_price - $node['Get Booking from Supabase'].json.amount_paid }}</span></div></div><div style=\"margin-bottom:32px;\"><h3 style=\"font-size:16px;font-weight:700;color:#1a472a;margin:0 0 16px;\">Session Prep</h3><div style=\"margin-bottom:12px;font-size:14px;color:#4b5563;line-height:1.5;\"><span style=\"color:#059669;font-weight:bold;margin-right:10px;\">✓</span><strong>Arrive 10 mins early</strong> — Grab a coffee and settle in before tee-off.</div><div style=\"margin-bottom:12px;font-size:14px;color:#4b5563;line-height:1.5;\"><span style=\"color:#059669;font-weight:bold;margin-right:10px;\">✓</span><strong>The Gear</strong> — Club rentals are available, or bring your own free of charge.</div><div style=\"margin-bottom:12px;font-size:14px;color:#4b5563;line-height:1.5;\"><span style=\"color:#059669;font-weight:bold;margin-right:10px;\">✓</span><strong>Clean Play</strong> — Ensure your gear is clean; sharpie marks damage our screens.</div></div><div style=\"text-align:center;margin-top:40px;\"><a href=\"https://maps.google.com/?q=38A+Chopin+St+Vanderbijlpark\" style=\"display:inline-block;background-color:#1a472a;color:#ffffff;padding:18px 36px;border-radius:12px;text-decoration:none;font-weight:700;font-size:16px;box-shadow:0 4px 12px rgba(26,71,42,0.2);\">Get Directions</a></div></div><div style=\"background-color:#f9fafb;padding:40px;text-align:center;border-top:1px solid #f3f4f6;\"><div style=\"color:#1a472a;font-size:18px;font-weight:800;margin-bottom:12px;\">The Mulligan</div><div style=\"font-size:13px;color:#9ca3af;margin-bottom:24px;line-height:1.5;\">38A Chopin St, Vanderbijlpark S.W. 5<br>Gauteng, South Africa</div><div style=\"font-size:11px;color:#9ca3af;\">&copy; 2026 The Mulligan Golf Lounge. All rights reserved.</div></div></div>"
