  "subject": "Reminder: Your Golf Simulator Booking is Tomorrow",
  "html": "<div style=\"font-family: 'Segoe UI', Arial, sans-serif; max-width: 580px; margin: 0 auto; color: #1f2937; background: #ffffff; border-radius: 12px; overflow: hidden; border: 1px solid #e5e7eb;\"><div style=\"background: linear-gradient(135deg, #166534 0%, #22c55e 100%); padding: 28px; text-align: center;\"><h1 style=\"color: white; margin: 0; font-size: 26px;\">⛳ See You Tomorrow!</h1><p style=\"color: rgba(255,255,255,0.9); margin: 8px 0 0; font-size: 15px;\">Your tee time is confirmed</p></div><div style=\"padding: 25px;\"><p style=\"font-size: 16px; margin: 0 0 15px;\">Hi <strong>{{ $node['Get Booking from Supabase'].json.guest_name }}</strong>,</p><p style=\"color: #6b7280; line-height: 1.6; margin: 0 0 20px;\">We're excited to have you at The Mulligan! Here's everything you need to know.</p><div style=\"background: linear-gradient(135deg, #f0fdf4 0%, #dcfce7 100%); border: 2px solid #22c55e; border-radius: 12px; padding: 20px; margin: 0 0 25px; text-align: center;\"><p style=\"margin: 0 0 8px; font-size: 22px; font-weight: bold; color: #166534;\">📅 {{ $node['Get Booking from Supabase'].json.booking_date }}</p><p style=\"margin: 0 0 8px; font-size: 20px; color: #166534;\">🕐 {{ $node['Get Booking from Supabase'].json.start_time }}</p><p style=\"margin: 0; font-size: 15px; color: #6b7280;\">📍 Bay {{ $node['Get Booking from Supabase'].json.simulator_id }}</p></div><div style=\"background: #fffbeb; border: 1px solid #f59e0b; border-radius: 12px; padding: 20px; margin: 0 0 20px;\"><p style=\"margin: 0 0 15px; font-weight: bold; color: #b45309; font-size: 15px; text-align: center;\">📋 THE MULLIGAN'S BASICS</p><ul style=\"margin: 0; padding-left: 20px; color: #4b5563; font-size: 14px; line-height: 1.9;\"><li style=\"margin-bottom: 8px;\"><strong>Arrive 15 mins early</strong> for smooth check-in</li><li style=\"margin-bottom: 8px;\"><strong>Bring your own clubs</strong> or rent with us</li><li style=\"margin-bottom: 8px;\"><strong>No spiked shoes, high heels</strong> – flat soles only</li><li style=\"margin-bottom: 8px;\"><strong>Golf glove is compulsory</strong> (available for purchase)</li><li style=\"margin-bottom: 8px;\"><strong>Clean balls & undamaged clubs only</strong> – protects our screens</li><li style=\"margin-bottom: 8px;\"><strong>🚫 No Sharpie-marked balls</strong> – they permanently damage screens!</li><li style=\"margin-bottom: 8px;\"><strong>Under 12s</strong> must be accompanied by an adult</li><li style=\"margin-bottom: 8px;\"><strong>Keep food & drinks off the turf</strong></li><li style=\"margin-bottom: 8px;\"><strong>No smoking/vaping indoors</strong></li></ul><p style=\"margin: 15px 0 0; padding-top: 12px; border-top: 1px solid #fcd34d; font-size: 12px; color: #92400e; text-align: center;\">⚠️ Staff reserves the right to stop play if rules aren't followed</p></div><div style=\"text-align: center; margin: 0 0 20px;\"><a href=\"https://maps.google.com/?q=38A+Chopin+St+Vanderbijlpark\" style=\"display: inline-block; background: #166534; color: white; padding: 12px 28px; border-radius: 8px; text-decoration: none; font-weight: bold; font-size: 14px;\">📍 Get Directions</a></div><p style=\"color: #6b7280; margin: 0; text-align: center;\">See you on the tee! 🏌️</p></div><div style=\"text-align: center; padding: 18px; background: #166534; color: rgba(255,255,255,0.9); font-size: 12px;\">38A Chopin St, Vanderbijlpark S.W. 5 | The Simulator Never Judges! ⛳</div></div>"
}

